import { NextResponse } from "next/server";

import { buildCartResponse } from "@/lib/api/cart-response";
import { getSession } from "@/lib/auth/session";
import { removeCartItem } from "@/lib/db/store";

export const dynamic = "force-dynamic";

interface RouteContext {
  params: { medicineId: string };
}

export async function DELETE(_req: Request, ctx: RouteContext): Promise<Response> {
  const session = getSession();
  if (!session) {
    return NextResponse.json({ error: "unauthenticated" }, { status: 401 });
  }
  const medicineId = (ctx.params.medicineId ?? "").trim();
  if (!medicineId) {
    return NextResponse.json({ error: "medicineId path param is required" }, { status: 400 });
  }
  removeCartItem(session.retailerId, medicineId);
  return NextResponse.json(buildCartResponse(session.retailerId));
}

import { NextResponse } from "next/server";

import { buildCartResponse } from "@/lib/api/cart-response";
import { getSession } from "@/lib/auth/session";
import { addCartItem, getMedicine } from "@/lib/db/store";

export const dynamic = "force-dynamic";

interface AddItemBody {
  medicineId?: string;
  qty?: number;
}

export async function POST(req: Request): Promise<Response> {
  const session = getSession();
  if (!session) {
    return NextResponse.json({ error: "unauthenticated" }, { status: 401 });
  }
  let body: AddItemBody;
  try {
    body = (await req.json()) as AddItemBody;
  } catch {
    return NextResponse.json({ error: "invalid JSON body" }, { status: 400 });
  }
  const medicineId = (body.medicineId ?? "").trim();
  if (!medicineId) {
    return NextResponse.json({ error: "medicineId is required" }, { status: 400 });
  }
  const qty = Number.isFinite(body.qty) && (body.qty as number) >= 1 ? Math.floor(body.qty as number) : 1;
  if (!getMedicine(medicineId)) {
    return NextResponse.json({ error: "medicine not found" }, { status: 404 });
  }
  addCartItem(session.retailerId, medicineId, qty);
  return NextResponse.json(buildCartResponse(session.retailerId));
}

import { NextResponse } from "next/server";

import { buildCartResponse } from "@/lib/api/cart-response";
import { getSession } from "@/lib/auth/session";

export const dynamic = "force-dynamic";

export async function GET(): Promise<Response> {
  const session = getSession();
  if (!session) {
    return NextResponse.json({ error: "unauthenticated" }, { status: 401 });
  }
  return NextResponse.json(buildCartResponse(session.retailerId));
}

import { getDistributor, getMedicine, listCartItems } from "@/lib/db/store";

export interface CartLine {
  medicineId: string;
  name: string;
  brand: string;
  qty: number;
  unitPricePaise: number;
  lineTotalPaise: number;
}

export interface CartGroup {
  distributor: { id: string; name: string };
  items: CartLine[];
  subtotalPaise: number;
}

export interface CartResponse {
  groups: CartGroup[];
  grandTotalPaise: number;
  itemCount: number;
}

export function buildCartResponse(retailerId: string): CartResponse {
  const items = listCartItems(retailerId);
  const groupsMap = new Map<string, CartGroup>();
  let grandTotalPaise = 0;
  let itemCount = 0;

  for (const item of items) {
    const med = getMedicine(item.medicineId);
    if (!med) continue;
    const dist = getDistributor(item.distributorId);
    const distributor = dist
      ? { id: dist.id, name: dist.name }
      : { id: item.distributorId, name: "Unknown distributor" };

    const lineTotal = item.qty * item.unitPricePaise;
    grandTotalPaise += lineTotal;
    itemCount += item.qty;

    let group = groupsMap.get(item.distributorId);
    if (!group) {
      group = { distributor, items: [], subtotalPaise: 0 };
      groupsMap.set(item.distributorId, group);
    }
    group.items.push({
      medicineId: item.medicineId,
      name: med.name,
      brand: med.brand,
      qty: item.qty,
      unitPricePaise: item.unitPricePaise,
      lineTotalPaise: lineTotal,
    });
    group.subtotalPaise += lineTotal;
  }

  const groups = Array.from(groupsMap.values()).sort((a, b) =>
    a.distributor.name.localeCompare(b.distributor.name),
  );
  return { groups, grandTotalPaise, itemCount };
}

